/**
 * Merge object b with object a.
 *
 * This utility function is used by Express.js to combine object properties.
 * It performs a shallow copy of all enumerable properties from one object to another.
 *
 * @param {Object} a Destination object
 * @param {Object} b Source object
 * @return {Object} Reference to modified object a
 * @public
 */
exports = module.exports = function(a, b) {
  if (a && b) {
    for (var key in b) {
      a[key] = b[key];
    }
  }
  
  return a;
};